using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// Uses constructor injection ŌĆö the SDK resolves HttpClient and ILogger
/// automatically; they never appear in the tool schema exposed to LLMs.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List all resources from the API. Returns a JSON array.")]
    public async Task<string> ListResources(
        [Description("Maximum number of items to return (1-100)")] int limit = 20,
        [Description("Zero-based page offset")] int offset = 0,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing resources (limit={Limit}, offset={Offset})", limit, offset);
        var json = await httpClient.GetStringAsync(
            $"/posts?_limit={limit}&_start={offset}", cancellationToken);
        return json;
    }

    [McpServerTool, Description("Get a single resource by its numeric ID.")]
    public async Task<string> GetResource(
        [Description("The unique numeric identifier of the resource")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching resource {Id}", id);
        var response = await httpClient.GetAsync($"/posts/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool(Destructive = false, ReadOnly = false),
     Description("Create a new resource. Returns the created object as JSON.")]
    public async Task<string> CreateResource(
        [Description("Title of the new resource")] string title,
        [Description("Body text / content of the resource")] string body,
        [Description("Author user ID")] int userId = 1,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating resource for user {UserId}", userId);
        var payload = JsonSerializer.Serialize(new { title, body, userId }, JsonOptions);
        var content = new StringContent(payload, Encoding.UTF8, "application/json");

        var response = await httpClient.PostAsync("/posts", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Search resources by keyword in the title field.")]
    public async Task<string> SearchResources(
        [Description("Keyword to search for in resource titles")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching resources for '{Query}'", query);
        var json = await httpClient.GetStringAsync(
            $"/posts?title_like={Uri.EscapeDataString(query)}", cancellationToken);
        return json;
    }
}

