using ApiMcpServer.Tools;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

var builder = Host.CreateApplicationBuilder(args);

// Logging MUST go to stderr ŌĆö stdout is the MCP JSON-RPC transport.
builder.Logging.AddConsole(o => o.LogToStandardErrorThreshold = LogLevel.Trace);

// Register a named HttpClient pointing at the target REST API.
// The SDK will inject this into ApiTools via constructor injection.
builder.Services.AddHttpClient<ApiTools>(client =>
{
    client.BaseAddress = new Uri("https://jsonplaceholder.typicode.com");
    client.DefaultRequestHeaders.Add("Accept", "application/json");
});

// Wire up the MCP server with stdio transport and attribute-discovered tools.
builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();   // finds every [McpServerToolType] in this assembly

await builder.Build().RunAsync();

